    // Cách này giúp code hoạt động cho mọi nền tảng (X, Tele, YT)
    return [{
        json: {
            ...parsedData, // Giải nén toàn bộ dữ liệu đã parse vào đây
            metadata_execution: {
                exitCode: item.exitCode,
                stderr: item.stderr
            }
        }
    }];

} catch (error) {
    // 5. Trường hợp stdout không phải JSON (có thể là log hoặc lỗi text)
    return [{
        json: {
            status: "parse_error",
            message: "Không thể parse JSON từ stdout. Có thể script gặp lỗi hoặc trả về text.",
            error_detail: error.message,
            raw_stdout: stdout
        }
    }];
}

const input = $input.first().json;

const stderr = input.stderr || '';
const stdout = input.stdout || '';

const hashtagSet = new Set(); // Sửa thành new Set()

// 1️⃣ Regex check lỗi
const ERROR_REGEX = /\b(error|exception|traceback|fatal|failed|timeout|panic|unhandled)\b/i;
const hasError = ERROR_REGEX.test(stderr);

// 2️⃣ Parse stdout string -> JSON
let parsedData = null;
let parseError = null;

if (stdout) {
  try {
    // Nếu stdout là chuỗi JSON, parse nó. Nếu đã là Object thì dùng luôn.
    parsedData = typeof stdout === 'string' ? JSON.parse(stdout) : stdout;

    // Đảm bảo parsedData là mảng để lặp
    const dataArray = Array.isArray(parsedData) ? parsedData : [parsedData];

    for (const item of dataArray) {
      // Giả sử item.tags và item.hashtags là mảng các chuỗi
      if (item.tags) item.tags.forEach(t => hashtagSet.add(t.toLowerCase()));
      if (item.hashtags) item.hashtags.forEach(h => hashtagSet.add(h.toLowerCase()));
    }
  } catch (err) {
    parseError = err.message;
  }
}

// 3️⃣ Return kết quả
return {
  hasError,
  parsed: Boolean(parsedData),
  parseError,
  data: parsedData,
  uniqueHashtags: Array.from(hashtagSet) // Chuyển Set về Array để n8n hiển thị được
};

