// 1. Lấy dữ liệu từ body của Webhook
const data = $('Webhook').item.json.body;

// 2. Trích xuất các trường dữ liệu (khớp chính xác với JSON bạn gửi)
const raw_platforms = data["Platform"] || "";
const keyword = (data["Từ khoá chính"] || "atx").toLowerCase();
const limit = data["Limit"] || 20;
const language = data["Language"] || "all";
const scrape_command = "hashtag"; // Mặc định theo logic cũ của bạn

// 3. Xử lý Platform (ép kiểu về mảng để loop)
const platforms = Array.isArray(raw_platforms) 
  ? raw_platforms 
  : raw_platforms.split(',').map(p => p.trim());

// 4. Xử lý thời gian (Chuyển đổi định dạng DD-MM-YYYY sang Timestamp)
// Lưu ý: JS Date hiểu chuẩn MM-DD-YYYY hoặc YYYY-MM-DD tốt hơn, 
// nhưng nếu format là DD-MM-YYYY ta cần xử lý một chút để tránh lỗi NaN.
const parseDate = (dateStr) => {
  if (!dateStr) return 0;
  const parts = dateStr.split('-');
  if (parts.length === 3) {
    // Chuyển DD-MM-YYYY thành YYYY-MM-DD để Date() đọc chính xác
    return new Date(`${parts[2]}-${parts[1]}-${parts[0]}`).getTime();
  }
  return new Date(dateStr).getTime() || 0;
};

const start_time = parseDate(data["Thời gian bắt đầu"]);
const end_time = parseDate(data["Thời gian kết thúc"]);

const path_cmd = "/home/dambui/platform-scraper/venv/bin/python /home/dambui/platform-scraper/main.py";
const cmd = [];

// 5. Vòng lặp tạo câu lệnh cho từng platform
for (let p of platforms) {
  if (!p) continue;
  p = p.toLowerCase().trim();
  let p_cmd = null;

  if (p === 'youtube') {
    p_cmd = `${path_cmd} youtube ${scrape_command} '${keyword}' --limit ${limit} --lang '${language}' --start-time '${start_time}' --end-time '${end_time}' --no-headless`;
  } else if (p === 'telegram') {
    p_cmd = `${path_cmd} telegram ${scrape_command}-async '${keyword}' --limit ${limit} --lang '${language}' --start-time '${start_time}' --end-time '${end_time}' --target 'all' --no-headless`;
  } else if (p === 'x' || p === 'twitter') {
    p_cmd = `${path_cmd} x ${scrape_command} '${keyword}' --limit ${limit} --lang '${language}' --start-time '${start_time}' --end-time '${end_time}' --headless`;
  }

  if (p_cmd) {
    cmd.push({ platform: p, p_cmd });
  }
}

// 6. Trả về kết quả
return [{
  json: {
    cmd: cmd,
    total: cmd.length
  }
}];

