// 1. Lấy toàn bộ danh sách items từ node trước
const allItems = $input.all();
const results = [];

// 2. Thử lấy Limit từ node cấu hình (nếu có)
let globalLimit;
try {
  globalLimit = $('When Executed by Another Workflow').first().json.Limit;
} catch (e) {
  globalLimit = null;
}

// 3. Lặp qua từng hashtag item (ví dụ: crypto, bitcoin, v.v.)
for (const item of allItems) {
  const data = item.json;

  if (!data.hashtag || !data.profiles) continue;

  const keyword_hashtag = data.hashtag.display_name;
  const platform = data.hashtag.platform;
  const profiles = data.profiles || [];

  // Xác định số lượng profile cần lấy cho hashtag này
  const currentLimit = globalLimit || profiles.length;
  const limitedProfiles = profiles.slice(0, currentLimit);

  // 4. Biến đổi từng profile của hashtag này thành 1 item riêng biệt
  for (const profile of limitedProfiles) {
    results.push({
      json: {
        ...profile,
        platform,
        keyword_hashtag,
        short_info: `
- username: ${profile.username}
- title: ${profile.display_name}
- Bio: ${profile.bio || 'N/A'}
- followers: ${profile.followers}
- following: ${profile.following}
- tweets_count: ${profile.tweets_count}
- joined_date: ${profile.joined_date}
- is_verified: ${profile.is_verified}
        `,
        cmd: `/home/dambui/platform-scraper/venv/bin/python /home/dambui/platform-scraper/main.py x posts '${profile.username}' -l 60 --headless`
      }
    });
  }
}

// 5. Trả về toàn bộ danh sách profiles của tất cả hashtags
return results;

// Lấy toàn bộ dữ liệu từ node trước đó
const inputData = items[0].json;

let allChannels = [];

// Trường hợp dữ liệu là mảng nhiều nhóm hashtag
if (Array.isArray(inputData)) {
  inputData.forEach(item => {
    if (item.channels && Array.isArray(item.channels)) {
      allChannels.push(...item.channels);
    }
  });
} 
// Trường hợp dữ liệu chỉ là 1 object đơn lẻ
else if (inputData.channels && Array.isArray(inputData.channels)) {
  allChannels = inputData.channels;
}

// Loại bỏ các channel trùng lặp dựa trên channel_id (nếu cần)
const uniqueChannels = Array.from(new Map(allChannels.map(ch => [ch.channel_id, ch])).values());

// Trả về định dạng items cho n8n
return uniqueChannels.map(channel => {
  return {
    json: channel
  };
});
